package com.example.bankingapp;

import android.os.Bundle;
import android.os.Handler;
import android.os.Looper;
import android.text.InputType;
import android.text.TextUtils;
import android.view.Gravity;
import android.view.ViewGroup;
import android.widget.Button;
import android.widget.EditText;
import android.widget.LinearLayout;
import android.widget.ScrollView;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.Locale;

public class MainActivity extends AppCompatActivity {

    private final Handler mainHandler = new Handler(Looper.getMainLooper());

    private TextView balanceView;
    private TextView statusView;
    private EditText amountInput;
    private EditText recipientInput;

    private BigDecimal balance = new BigDecimal("1250.00");

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        ScrollView scrollView = new ScrollView(this);
        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        root.setPadding(dp(16), dp(16), dp(16), dp(16));
        root.setLayoutParams(new ViewGroup.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT
        ));

        TextView title = new TextView(this);
        title.setText("Banking Module");
        title.setTextSize(24f);
        title.setGravity(Gravity.CENTER_HORIZONTAL);

        balanceView = new TextView(this);
        balanceView.setTextSize(20f);
        balanceView.setPadding(0, dp(16), 0, dp(16));

        recipientInput = new EditText(this);
        recipientInput.setHint("Recipient / Account ID");
        recipientInput.setInputType(InputType.TYPE_CLASS_TEXT);
        recipientInput.setLayoutParams(new LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
        ));

        amountInput = new EditText(this);
        amountInput.setHint("Amount");
        amountInput.setInputType(InputType.TYPE_CLASS_NUMBER | InputType.TYPE_NUMBER_FLAG_DECIMAL);
        amountInput.setLayoutParams(new LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
        ));

        Button transferButton = new Button(this);
        transferButton.setText("Process Transaction");

        statusView = new TextView(this);
        statusView.setTextSize(14f);
        statusView.setPadding(0, dp(16), 0, 0);

        transferButton.setOnClickListener(v -> processTransaction());

        root.addView(title);
        root.addView(balanceView);
        root.addView(recipientInput);
        root.addView(amountInput);
        root.addView(transferButton);
        root.addView(statusView);

        scrollView.addView(root);
        setContentView(scrollView);

        updateBalanceDisplay();
        setStatus("Ready");
    }

    private void processTransaction() {
        String recipient = safeText(recipientInput);
        String amountText = safeText(amountInput);

        if (TextUtils.isEmpty(recipient)) {
            setStatus("Recipient is required");
            Toast.makeText(this, "Please enter a recipient", Toast.LENGTH_SHORT).show();
            return;
        }

        BigDecimal amount;
        try {
            amount = new BigDecimal(amountText).setScale(2, RoundingMode.HALF_UP);
        } catch (Exception e) {
            setStatus("Invalid amount");
            Toast.makeText(this, "Enter a valid amount", Toast.LENGTH_SHORT).show();
            return;
        }

        if (amount.compareTo(BigDecimal.ZERO) <= 0) {
            setStatus("Amount must be greater than zero");
            Toast.makeText(this, "Amount must be greater than zero", Toast.LENGTH_SHORT).show();
            return;
        }

        if (amount.compareTo(balance) > 0) {
            setStatus("Insufficient funds");
            Toast.makeText(this, "Insufficient funds", Toast.LENGTH_SHORT).show();
            return;
        }

        setStatus("Processing transaction...");
        mainHandler.postDelayed(() -> {
            balance = balance.subtract(amount).setScale(2, RoundingMode.HALF_UP);
            updateBalanceDisplay();
            setStatus(String.format(Locale.US, "Transferred %s to %s", formatMoney(amount), recipient));
            Toast.makeText(this, "Transaction complete", Toast.LENGTH_SHORT).show();
            amountInput.setText("");
        }, 600);
    }

    private void updateBalanceDisplay() {
        balanceView.setText(String.format(Locale.US, "Available Balance: %s", formatMoney(balance)));
    }

    private void setStatus(String message) {
        statusView.setText(message);
    }

    private String formatMoney(BigDecimal value) {
        return String.format(Locale.US, "$%,.2f", value);
    }

    private String safeText(EditText editText) {
        CharSequence cs = editText.getText();
        return cs == null ? "" : cs.toString().trim();
    }

    private int dp(int value) {
        float density = getResources().getDisplayMetrics().density;
        return Math.round(value * density);
    }
}